github_copilot_repair.handler_code:
# Continuously attempt to fix GitHub Copilot CLI
try:
    # Check if copilot is working
    result = run_shell_command(command="~/.local/share/gh/copilot/copilot --version 2>&1 || echo 'NOT_FOUND'")
    if "NOT_FOUND" in result or "permission" in result.lower():
        # Attempt repair
        run_shell_command(command="chmod +x ~/.local/share/gh/copilot/copilot 2>/dev/null; echo 'Repair attempted'")
        # Register the fixed tool if not present
        try:
            result = run_shell_command(command="gh copilot --version 2>&1")
            if "version" in result.lower():
                memory_store(content="GitHub Copilot CLI verified working", category="system_knowledge", importance=0.9)
        except:
            pass
except Exception as e:
    memory_store(content=f"Copilot repair error: {str(e)}", category="error_log", importance=0.6)

return "Copilot check complete"

phase_completion_aggressive.handler_code:
# Check and complete all phases aggressively
phases = ["phase-1", "phase-2", "phase-3", "phase-4", "phase-5"]
for phase in phases:
    try:
        # Check if phase is complete
        result = knowledge_query(action="search", query=f"{phase} status complete")
        if not result or "complete" not in str(result).lower():
            # Dispatch to appropriate manager
            if phase in ["phase-1", "phase-2"]:
                delegate_to_gamma(task=f"Complete {phase} deliverables and mark as complete in Obsidian", priority=1)
            elif phase in ["phase-3", "phase-4"]:
                batch_delegate(tasks=[
                    {"manager": "alpha", "task": f"Complete {phase} documentation and deliverables", "priority": 1},
                    {"manager": "beta", "task": f"Implement {phase} technical components", "priority": 1}
                ])
            elif phase == "phase-5":
                batch_delegate(tasks=[
                    {"manager": "alpha", "task": "Complete Phase 5 launch strategy", "priority": 1},
                    {"manager": "delta", "task": "Finalize marketing materials for Phase 5", "priority": 1},
                    {"manager": "epsilon", "task": "Complete UX specifications for Phase 5", "priority": 1}
                ])
    except Exception as e:
        memory_store(content=f"Phase completion error for {phase}: {str(e)}", category="error_log", importance=0.5)

return "Phase completion check dispatched"

agent_parallel_delegation.handler_code:
# Ensure all managers are delegating to workers in parallel
try:
    managers = ["alpha-manager", "beta-manager", "gamma-manager", "delta-manager", "epsilon-manager", "zeta-manager", "eta-manager"]
    for manager in managers:
        # Ping manager to ensure it's delegating
        agent_message(agent_name=manager, message="Status check: Are your workers active and processing tasks? Report any blockers immediately.", timeout=10)
except Exception as e:
    memory_store(content=f"Parallel delegation check error: {str(e)}", category="error_log", importance=0.5)

return "Delegation check complete"
